import React, { useState, useEffect } from "react";
import "./Internship.css";

export default function Internship() {
  const user = JSON.parse(localStorage.getItem("loggedInUser")) || {};
  const [internships, setInternships] = useState([]);
  const [newInternship, setNewInternship] = useState({
    title: "",
    company: "",
    description: "",
  });

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("internships")) || [];
    setInternships(stored);
  }, []);

  const handleAdd = () => {
    const updated = [...internships, newInternship];
    localStorage.setItem("internships", JSON.stringify(updated));
    setInternships(updated);
    setNewInternship({ title: "", company: "", description: "" });
  };

  const handleDelete = (index) => {
    const updated = internships.filter((_, i) => i !== index);
    localStorage.setItem("internships", JSON.stringify(updated));
    setInternships(updated);
  };

  const handleApply = (index) => {
    alert(`Applied to: ${internships[index].title} at ${internships[index].company}`);
  };

  const isAdminOrHR = user.role === "Admin" || user.role === "HR";

  return (
    <div className="internship-container">
      <h1>Internship Opportunities</h1>

      {isAdminOrHR && (
        <div className="form-section">
          <input
            type="text"
            placeholder="Title"
            value={newInternship.title}
            onChange={(e) => setNewInternship({ ...newInternship, title: e.target.value })}
          />
          <input
            type="text"
            placeholder="Company"
            value={newInternship.company}
            onChange={(e) => setNewInternship({ ...newInternship, company: e.target.value })}
          />
          <textarea
            placeholder="Description"
            value={newInternship.description}
            onChange={(e) => setNewInternship({ ...newInternship, description: e.target.value })}
          />
          <button onClick={handleAdd}>Add Internship</button>
        </div>
      )}

      <div className="card-grid">
        {internships.map((item, index) => (
          <div key={index} className="internship-card">
            <h3>{item.title}</h3>
            <h4>{item.company}</h4>
            <p>{item.description}</p>

            {user.role === "Student" && (
              <button className="apply-btn" onClick={() => handleApply(index)}>
                Apply
              </button>
            )}

            {isAdminOrHR && (
              <button className="delete-btn" onClick={() => handleDelete(index)}>
                Delete
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
